#include<bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
int n,d,qm[MAXN],qn[MAXN],ans;
int hm,hn,td,tn;
struct wate
{
	int x,y;
	bool operator<(const wate&a)const
	{
		return x<a.x;
	}
}a[MAXN];
void solve()
{
    hm=hn=1;tn=td=0;
    int l=1;
    ans=llinf;
    FOR(i,1,n)
    {
        wh(hm<=td&&a[i].y>a[qm[td]].y)td--;
        qm[++td]=i;
        wh(hn<=tn&&a[i].y<a[qn[tn]].y)tn--;
        qn[++tn]=i;
        wh(l<=i&&a[qm[hm]].y-a[qn[hn]].y>=d)
        {
            ans=min(ans,a[i].x-a[l].x);
            l++;
            wh(hm<=td&&qm[hm]<l)hm++;
            wh(hn<=tn&&qn[hn]<l)hn++;
        }
    }
}

signed main(void)
{
    n=read();d=read();
    FOR(i,1,n)
    {
        a[i].x=read();
        a[i].y=read();
    }
    sort(a+1,a+1+n);
    solve();
    if(ans<llinf)
    {
        writeln(ans);
    }
    else
    {
        NoAns
    }
    return false;
}
